import requests

def get_techniques_for_tactic(tactic_name):
    # ATT&CK STIX/TAXII endpoint (example URL)
    url = f"https://api.example.com/attack/stix/enterprise/latest/tactics/{tactic_name}/techniques/"
    response = requests.get(url)
    if response.status_code == 200:
        return response.json()
    else:
        return None

# Example usage:
techniques = get_techniques_for_tactic("privilege-escalation")
print(techniques)
